import base64
from google.cloud import pubsub_v1
from cloud_functions.util.datastore_service import DataStoreService
from cloud_functions.util.task_service import TaskService
import pickle

def process_batch_job(message):
    try:
        message_bytes = base64.b64decode(message['data'])
        data = pickle.loads(message_bytes)
        
        task_id = message['attributes']['task_id']
        result = TaskService.complete_task(task_id, data)

        DataStoreService.insert_batch_job_result(result)
    except Exception as e:
        print(f"Error processing batch job: {str(e)}")

def pull_process_and_ack(pubsub_client, subscription_path):
    subscriber = pubsub_v1.SubscriberClient()
    subscription_name = subscription_path

    pull_future = subscriber.pull(subscription_name=subscription_name, max_messages=10)
    messages = []

    while (pull_future is not None) and (pull_future.result().received_messages):
        messages.extend(pull_future.result().received_messages)

        if len(messages) < 10:
            break
        else:
            pull_future = subscriber.pull(subscription_name=subscription_name, max_messages=10)

    for message in messages:
        try:
            process_batch_job(message)
            ack_pubsub_message(subscriber, subscription_name, message.message_id)
        except Exception as e:
            print(f"Error processing batch job: {str(e)}")

def ack_pubsub_message(subscriber, subscription_name, message_id):
    subscriber.acknowledge(subscription_name=subscription_name, messages=[message_id])